import * as XLSX from 'xlsx';
import dayjs from 'dayjs';
import customParseFormat from 'dayjs/plugin/customParseFormat.js';
import minMax from 'dayjs/plugin/minMax.js';

dayjs.extend(customParseFormat);
dayjs.extend(minMax);

export const processCombinedData = (csvData, excelRaw, proyectadoManual = 239000) => {
  // --- 1. PROCESAR EXCEL (EASY DOCKING) ---
  const workbook = XLSX.read(excelRaw, { type: 'array' });
  const sheet = workbook.Sheets[workbook.SheetNames[0]];
  const rows = XLSX.utils.sheet_to_json(sheet, { header: 1 });

  const headers = rows[3]?.map(h => String(h || "").trim()) || [];
  const dataRows = rows.slice(4);

  const easyDockingClean = dataRows.map(row => {
    let obj = {};
    headers.forEach((h, i) => obj[h] = row[i]);
    return obj;
  }).filter(item => 
    String(item['TIPO DE OPERACION'] || "").toUpperCase().includes("DESCARGA") && 
    String(item['Accion'] || "").toLowerCase() === "add"
  );

  // --- 2. LÓGICA DE TIEMPO (HASTA LAS 22:00) ---
  const ahora = dayjs();
  const horaCierre = dayjs().set('hour', 22).set('minute', 0).set('second', 0);
  let horasRestantes = horaCierre.diff(ahora, 'hour', true);
  if (horasRestantes <= 0) horasRestantes = 0.5;

  // --- 3. CÁLCULOS POR TIPO DE VEHÍCULO (MATRIX) ---

  // Función auxiliar para calcular piezas por tipo
  const getStatsByTransporte = (tipos, totalProyectadoSector) => {
    const filtrados = easyDockingClean.filter(d => 
      tipos.some(tipo => String(d['TRANSPORTE'] || "").includes(tipo))
    );

    const piezasDescargadas = filtrados.reduce((acc, curr) => 
      acc + (parseFloat(curr['CANT PAQUETES']) || 0), 0
    );

    // Velocidad requerida para este sector específico
    const objHoraSector = Math.round((totalProyectadoSector - piezasDescargadas) / horasRestantes);

    return objHoraSector > 0 ? objHoraSector : 0;
  };

  // Definimos proyectados por sector (puedes ajustarlos aquí o en Parámetros después)
  // Basado en tus 'Planificados' de la imagen: 1200, 500, 300
  const matrix = {
    chasis: getStatsByTransporte(['Chasis'], 120000), // Ejemplo: meta 120k piezas
    camioneta: getStatsByTransporte(['Camioneta', 'Camioneta MELI'], 50000), // meta 50k
    semi: getStatsByTransporte(['Semi'], 30000) // meta 30k
  };

  // --- 4. KPIs GLOBALES (Lo que ya teníamos) ---
  const totalArribados = easyDockingClean.reduce((acc, curr) => acc + (parseFloat(curr['CANT PAQUETES']) || 0), 0);
  const totalSistema = csvData.filter(d => d['Shipment ID']).length;

  return {
    kpis: {
      proyectado: proyectadoManual.toLocaleString(),
      arribados: totalArribados.toLocaleString(),
      total: totalSistema.toLocaleString(),
      descargaHora: Math.round((proyectadoManual - totalSistema) / horasRestantes).toLocaleString(),
      pArribado: Math.round((totalArribados / proyectadoManual) * 100) || 0,
      pBipeo: Math.round((totalSistema / proyectadoManual) * 100) || 0,
      velocidadReal: 90 // SPR
    },
    matrix, // Aquí van los nuevos Obj x Hora por transporte
    chartData: [], 
    tableData: []
  };
};
